  `birim_fiyat` decimal(10,2) NOT NULL DEFAULT 0.00,
  `kdv_orani` decimal(5,2) NOT NULL DEFAULT 18.00,
  `stok_miktari` decimal(10,3) NOT NULL DEFAULT 0.000 COMMENT 'Adet cinsinden ürünlerin stok miktarı',
  `stok_kg` decimal(10,3) NOT NULL DEFAULT 0.000 COMMENT 'Kilogram ve gram cinsinden ürünlerin stok miktarı',
  `minimum_stok` int(11) NOT NULL DEFAULT 5,
  `birim` varchar(20) DEFAULT 'Adet',
